    const dist = new Array(n).fill(0).map(() => new Array(2).fill(Infinity));
    dist[0][0] = 0; // 0: not used switch, 1: used switch

    const pq = new PriorityQueue((a, b) => a[0] - b[0]);
    pq.enqueue([0, 0, 0]); // [distance, node, switchUsed]

    while (!pq.isEmpty()) {
