function solve(n: number, edges: number[][]): number {
    const graph = new Array(n).fill(null).map(() => new Array());

    for (const [u, v, w] of edges) {
        graph[u].push({ to: v, weight: w });
    }

    const dist = new Array(n).fill(0).map(() => new Array(2).fill(Infinity));
    dist[0][0] = 0; // 0: not used switch, 1: used switch

    const pq = new PriorityQueue((a, b) => a[0] - b[0]);
    pq.enqueue([0, 0, 0]); // [distance, node, switchUsed]

    while (!pq.isEmpty()) {
        const [d, u, used] = pq.dequeue();

        if (u === n - 1) return d;

        if (d > dist[u][used]) continue;

        for (const { to, weight } of graph[u]) {
            // Regular edge
            if (used === 0) {
                const newDist = d + weight;
                if (newDist < dist[to][0]) {
                    dist[to][0] = newDist;
                    pq.enqueue([newDist, to, 0]);
                }
            }

            // Reverse edge (only if not used switch yet)
            if (used === 0) {
                const newDist = d + 2 * weight;
                if (newDist < dist[to][1]) {
                    dist[to][1] = newDist;
                    pq.enqueue([newDist, to, 1]);
                }
            }
        }
    }

    return -1;
}
